const text = $json.text || $json.raw_text || "";

/**
 * -----------------------------
 * Helpers
 * -----------------------------
 */

function matchRule(pattern) {
  if (!pattern) return null;
  const match = text.match(pattern);
  return match ? match[1]?.trim() : null;
}

function parseAmount(value) {
  if (!value) return null;

  const cleaned = String(value)
    .replace(/\s/g, "")
    .replace(/\./g, "")
    .replace(",", ".")
    .replace(/[^\d.-]/g, "");

  const number = Number(cleaned);
  return Number.isFinite(number) ? number : null;
}

function toIsoDate(value) {
  if (!value) return null;

  const match = String(value).match(/([0-9]{1,2})[.\-/]([0-9]{1,2})[.\-/]([0-9]{2,4})/);
  if (!match) return value;

  let [, d, m, y] = match;
  if (y.length === 2) y = `20${y}`;

  return `${y.padStart(4, "0")}-${m.padStart(2, "0")}-${d.padStart(2, "0")}`;
}

function normalizeIban(value) {
  if (!value) return null;

  const iban = value.replace(/\s+/g, "").toUpperCase();

  // Ignore masked IBANs
  if (iban.includes("*") || iban.includes("X")) return null;

  return iban;
}

function round2(value) {
  if (value === null || value === undefined) return null;
  return Math.round(value * 100) / 100;
}

/**
 * -----------------------------
 * Vendor-specific extractors
 * -----------------------------
 */

function extract1und1Amounts(text) {
  const grossMatch = text.match(/(?:Zu zahlender Betrag|Auszuzahlender Betrag)\s+([0-9.,]+)\s+EUR/i);
  const vatRateMatch = text.match(/Mehrwertsteuer\s*\(([0-9.,]+)%\)/i);

  const amountBlockMatch = text.match(
    /Zwischensumme\s+Netto\s*\n?\+?\s*Mehrwertsteuer\s*\([0-9.,]+%\)\s*\n?\s*(-?[0-9.,]+)\s+EUR\s*\n?\s*(-?[0-9.,]+)\s+EUR/i
  );

  let gross = parseAmount(grossMatch?.[1]);
  let net = parseAmount(amountBlockMatch?.[1]);
  let vat = parseAmount(amountBlockMatch?.[2]);
  const vatRate = parseAmount(vatRateMatch?.[1]);

  // Repair if extraction failed or VAT is implausible
  if (gross !== null && vatRate !== null) {
    const expectedNet = round2(gross / (1 + vatRate / 100));
    const expectedVat = round2(gross - expectedNet);

    const sumInvalid =
      net === null ||
      vat === null ||
      Math.abs(gross - (net + vat)) > 0.05;

    const vatTooHigh =
      vat !== null &&
      gross !== null &&
      Math.abs(vat / gross) > 0.3;

    if (sumInvalid || vatTooHigh) {
      net = expectedNet;
      vat = expectedVat;
    }
  }

  return {
    gross_amount: gross,
    net_amount: net,
    vat_amount: vat
  };
}

function applyVendorSpecificLogic(result, vendorId) {
  switch (vendorId) {
    case "1und1": {
      Object.assign(result, extract1und1Amounts(text));

      result.payment_method = /SEPA-Lastschriftmandat|buchen wir den Rechnungsbetrag/i.test(text)
        ? "SEPA-Lastschrift"
        : /gutschreiben|schreiben wir Ihnen.*gut|Gutschrift/i.test(text)
          ? "Gutschrift"
          : result.payment_method;

      result.iban = null;
      break;
    }

    default:
      break;
  }

  return result;
}

/**
 * -----------------------------
 * Vendor definitions
 * -----------------------------
 */

const vendors = [
  {
    id: "1und1",
    name: "1&1 Telecom GmbH",
    detect: /1\s*&\s*1\s+Telecom|1und1|1&1/i,
    rules: {
      invoice_number: /Rechnungsnummer:?\s+([0-9]+)/i,
      invoice_date: /Rechnungsdatum:?\s+([0-9]{2}\.[0-9]{2}\.[0-9]{4})/i,
      customer_number: /Kundennummer:?\s+([A-Z]?\d{6,})/i,
      order_number: /(?:Vertragsnummer|Vertrag):?\s+([0-9]+)/i,
      gross_amount: /(?:Zu zahlender Betrag|Auszuzahlender Betrag)\s+([0-9.,]+)\s+EUR/i,
      payment_method: /(SEPA-Lastschrift|Gutschrift|gutschreiben|schreiben wir Ihnen.*gut)/i,
      iban: null
    }
  },
  {
    id: "juwelier_bektas",
    name: "Juwelier Bektas e.K.",
    detect: /juwelier\s+bektas|bektas\.de|DE118210739/i,
    rules: {
      invoice_number: /Rechnungs-Nr\.\s*([A-Z]{2}-\d+)/i,
      invoice_date: /Rechnungsdatum\s*([0-9]{2}\.[0-9]{2}\.[0-9]{4})/i,
      order_number: /Auftragsnummer\s*(\d+)/i,
      customer_number: /Kundennummer\s*(\d+)/i,
      payment_method: /Zahlungsart\s*([A-Za-zÄÖÜäöüß ]+)/i,
      net_amount: /Zwischensumme\s*([0-9.,]+)\s*EUR/i,
      vat_amount: /MwSt\.\s*\(19,00\s*%\)\s*([0-9.,]+)\s*EUR/i,
      gross_amount: /Rechnungssumme\s*([0-9.,]+)\s*EUR/i,
      iban: /IBAN:\s*([A-Z]{2}[0-9A-Z]+)/i
    }
  },
  {
    id: "cyberport",
    name: "Cyberport",
    detect: /Cyberport SE|www\.cyberport\.de|cyberport/i,
    rules: {
      invoice_number: /Rechnungsnr\.?\/?-datum\s+([0-9]+)/i,
      invoice_date: /Rechnungsnr\.?\/?-datum\s+[0-9]+\s*\/\s*([0-9]{2}\.[0-9]{2}\.[0-9]{4})/i,
      customer_number: /Kunde\s+([0-9]+)/i,
      order_number: /Bestellnr\.?\/?-datum\s+([0-9]+)/i,
      gross_amount: /Gesamtbetrag\s+([0-9.,]+)\s+EUR/i,
      net_amount: /Nettobetrag\s+EUR\s+([0-9.,]+)\s+EUR/i,
      vat_amount: /Umsatzsteuer\s+[0-9.,]+%\s+auf\s+[0-9.,]+\s+EUR\s+([0-9.,]+)\s+EUR/i,
      iban: /IBAN:\s*([A-Z]{2}\s*[0-9]{2}(?:\s*[0-9A-Z]{4}){4}\s*[0-9A-Z]{2})/i
    }
  },
  {
    id: "hetzner",
    name: "Hetzner Online GmbH",
    detect: /hetzner/i,
    rules: {
      invoice_number: /Rechnungsnummer\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
      invoice_date: /Rechnungsdatum\s*[:#]?\s*([0-9]{2}\.[0-9]{2}\.[0-9]{4})/i,
      customer_number: /Kundennummer\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
      gross_amount: /Summe\s+[\s\S]*?([0-9.,]+)\s*€/i,
      net_amount: /Summe\s+([0-9.,]+)\s*€\s+[0-9.,]+\s*€/i,
      vat_amount: /Summe\s+[0-9.,]+\s*€\s+([0-9.,]+)\s*€/i,
      payment_method: /Der Betrag wird .*? abgebucht/i,
      iban: /IBAN:\s*([A-Z]{2}[0-9A-Z*X\s]+)/i
    }
  },
  {
    id: "check24",
    name: "CHECK24",
    detect: /check24/i,
    rules: {
      invoice_number: /Rechnung(?:snummer)?\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
      invoice_date: /Datum\s*[:#]?\s*([0-9]{2}\.[0-9]{2}\.[0-9]{4})/i,
      gross_amount: /Gesamt(?:betrag)?\s*[: ]+\s*([0-9.,]+)\s*€/i
    }
  }
];

/**
 * -----------------------------
 * Generic rules
 * -----------------------------
 */

const genericRules = {
  invoice_number: /(?:Rechnungsnummer|Rechnung Nr\.?|Invoice Number|Invoice No\.?)\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
  invoice_date: /(?:Rechnungsdatum|Invoice Date|Datum)\s*[:#]?\s*([0-9]{1,2}[.\-/][0-9]{1,2}[.\-/][0-9]{2,4})/i,
  customer_number: /(?:Kundennummer|Kunde|Customer Number|Customer No\.?)\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
  order_number: /(?:Bestellnummer|Bestellnr\.?|Auftragsnummer|Order Number|Order No\.?)\s*[:#]?\s*([A-Z0-9\-\/]+)/i,
  gross_amount: /(?:Gesamtbetrag|Bruttobetrag|Rechnungssumme|Total|Amount Due)\s*[: ]+\s*([0-9.,]+)\s*€?/i,
  vat_amount: /(?:MwSt|USt|Umsatzsteuer|VAT).*?([0-9.,]+)\s*€?/i,
  net_amount: /(?:Nettobetrag|Netto|Net Amount|Subtotal|Zwischensumme)\s*[: ]+\s*([0-9.,]+)\s*€?/i,
  iban: /(DE[0-9]{2}\s?(?:[0-9A-Z]{4}\s?){4}[0-9A-Z]{2})/i
};

/**
 * -----------------------------
 * Main parser
 * -----------------------------
 */

const vendor = vendors.find(v => v.detect.test(text));

const rules = {
  ...genericRules,
  ...(vendor?.rules || {})
};

let result = {
  processed_at: new Date().toISOString(),
  vendor_id: vendor?.id || "generic",
  vendor_name: vendor?.name || null,
  invoice_number: matchRule(rules.invoice_number),
  invoice_date: toIsoDate(matchRule(rules.invoice_date)),
  customer_number: matchRule(rules.customer_number),
  order_number: matchRule(rules.order_number),
  currency: "EUR",
  net_amount: parseAmount(matchRule(rules.net_amount)),
  vat_amount: parseAmount(matchRule(rules.vat_amount)),
  gross_amount: parseAmount(matchRule(rules.gross_amount)),
  payment_method: matchRule(rules.payment_method),
  iban: normalizeIban(matchRule(rules.iban)),
  source_filename: $json.source_filename || $json.fileName || null,
  status: "processed",
  parser: vendor ? "vendor_rule_based" : "generic_rule_based",
  source_confidence: 0,
  validation_error: null,
  raw_text: text
};

result = applyVendorSpecificLogic(result, result.vendor_id);

/**
 * -----------------------------
 * Validation
 * -----------------------------
 */

let validationErrors = [];

if (
  result.gross_amount !== null &&
  result.net_amount !== null &&
  result.vat_amount !== null
) {
  const diff = Math.abs(result.gross_amount - (result.net_amount + result.vat_amount));

  if (diff > 0.05) {
    validationErrors.push("gross_amount does not equal net_amount + vat_amount");
  }
}

if (
  result.vat_amount !== null &&
  result.gross_amount !== null &&
  Math.abs(result.vat_amount / result.gross_amount) > 0.3
) {
  validationErrors.push("VAT amount is unusually high");
}

if (validationErrors.length > 0) {
  result.validation_error = validationErrors.join("; ");
  result.status = "needs_review";
}

/**
 * -----------------------------
 * Confidence scoring
 * -----------------------------
 */

let confidence = 0;

if (result.vendor_name) confidence += 10;
if (result.invoice_number) confidence += 25;
if (result.invoice_date) confidence += 20;
if (result.gross_amount !== null) confidence += 25;
if (result.vat_amount !== null) confidence += 10;
if (result.net_amount !== null) confidence += 10;
if (result.customer_number) confidence += 5;
if (result.order_number) confidence += 5;

if (vendor) confidence += 10;
if (validationErrors.length > 0) confidence -= 30;

result.source_confidence = Math.max(0, Math.min(100, confidence));

return { json: result };

const date = $json.invoice_date;

if (date) {
  const [day, month, year] = date.split('.');
  $json.invoice_date = `${year}-${month}-${day}`;
}

return $input.item;

const parsed = JSON.parse($input.first().json.text)

if (parsed.iban && parsed.iban.includes("*")) {
  parsed.iban = null;
}

return [{
  json: {
    ...parsed,
    processed_at: parsed.processed_at || new Date().toISOString()
  }
}];

const date = new Date($json.invoice_date);

const year = date.getFullYear();
const month = String(date.getMonth() + 1).padStart(2, '0');
const day = String(date.getDate()).padStart(2, '0');

const filename =
  `${year}-${month}-${day}_` +
  `${$json.invoice_number}.pdf`
    .replace(/[^\w.-]/g, "_");

$json.file_path =
  `/opt/n8n/.n8n/invoices/${year}/${month}/${filename}`;

return $input.item;
